Here's how to test `DataFetcher` with MSTest, covering success, failure, timeout, and cancellation:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    private readonly TestContext _testContext;

    public DataFetcherTests(TestContext testContext)
    {
        _testContext = testContext;
    }

    private static (DataFetcher fetcher, MockHttpMessageHandler handler) CreateFetcher()
    {
        var handler = new MockHttpMessageHandler();
        var client = new HttpClient(handler) { BaseAddress = new Uri("https://example.com") };
        return (new DataFetcher(client), handler);
    }

    [TestMethod]
    public async Task FetchAsync_SuccessResponse_ReturnsContent()
    {
        // Arrange
        var (fetcher, handler) = CreateFetcher();
        handler.ResponseContent = "hello world";

        // Act
        var result = await fetcher.FetchAsync("https://example.com/data",
            _testContext.CancellationToken);

        // Assert
        Assert.AreEqual("hello world", result);
    }

    [TestMethod]
    public async Task FetchAsync_NotFound_ThrowsHttpRequestException()
    {
        // Arrange
        var (fetcher, handler) = CreateFetcher();
        handler.StatusCode = System.Net.HttpStatusCode.NotFound;

        // Act & Assert
        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            async () => await fetcher.FetchAsync("https://example.com/missing",
                _testContext.CancellationToken));
    }

    [TestMethod]
    public async Task FetchAsync_CancellationRequested_ThrowsTaskCanceledException()
    {
        // Arrange
        var (fetcher, handler) = CreateFetcher();
        handler.SimulateDelay = TimeSpan.FromSeconds(30);
        using var cts = new CancellationTokenSource();
        cts.Cancel(); // cancel immediately

        // Act & Assert
        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync("https://example.com/slow", cts.Token));
    }

    [TestMethod]
    [Timeout(5000)] // fails test if it takes longer than 5s
    public async Task FetchAsync_CompletesWithinTimeout()
    {
        // Arrange
        var (fetcher, handler) = CreateFetcher();
        handler.ResponseContent = "fast";

        // Act — pass TestContext.CancellationToken so [Timeout] can cancel cooperatively
        var result = await fetcher.FetchAsync("https://example.com/data",
            _testContext.CancellationToken);

        // Assert
        Assert.AreEqual("fast", result);
    }

    [TestMethod]
    public async Task FetchAsync_PassesCancellationTokenToHttpClient()
    {
        // Arrange
        var (fetcher, handler) = CreateFetcher();
        handler.ResponseContent = "ok";

        // Act
        await fetcher.FetchAsync("https://example.com/data", _testContext.CancellationToken);

        // Assert — verify the token was forwarded
        Assert.AreEqual(_testContext.CancellationToken, handler.ReceivedCancellationToken);
    }

    // Minimal test double — no mocking framework needed
    private sealed class MockHttpMessageHandler : HttpMessageHandler
    {
        public string ResponseContent { get; set; } = "";
        public System.Net.HttpStatusCode StatusCode { get; set; } = System.Net.HttpStatusCode.OK;
        public TimeSpan SimulateDelay { get; set; } = TimeSpan.Zero;
        public CancellationToken ReceivedCancellationToken { get; private set; }

        protected override async Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            ReceivedCancellationToken = cancellationToken;
            cancellationToken.ThrowIfCancellationRequested();

            if (SimulateDelay > TimeSpan.Zero)
                await Task.Delay(SimulateDelay, cancellationToken);

            return new HttpResponseMessage(StatusCode)
            {
                Content = new StringContent(ResponseContent),
            };
        }
    }
}
```

**Key patterns demonstrated:**

| Pattern | How |
|---|---|
| **Cooperative timeout** | `[Timeout(5000)]` + `_testContext.CancellationToken` — MSTest cancels the token when time expires |
| **Cancellation** | Create a pre-cancelled `CancellationTokenSource`, assert `TaskCanceledException` |
| **Token forwarding** | Capture the token in the handler, verify it matches what was passed |
| **No `[ExpectedException]`** | Use `Assert.ThrowsExactlyAsync<T>` — it's precise and lets you inspect the exception |
| **Sealed class + ctor injection** | `TestContext` injected via constructor, class is `sealed` for performance |

The `MockHttpMessageHandler` avoids needing a mocking library — `HttpClient` delegates all calls to its inner handler, making this the standard seam for testing HTTP code.
